from collections import defaultdict

def detect_loops(messages, max_turns=20):
    speaker_seq = [msg.get('name', 'unknown') for msg in messages[-max_turns:]]
    seq_str = ' -> '.join(speaker_seq)
    if seq_str in ['Agent1 -> Agent2 -> Agent1 -> Agent2', 'Critic -> Coder -> Critic']:
        return {'issue': 'infinite_loop', 'pattern': seq_str}
    return None

import re

def detect_unsafe_code(content):
    dangerous_patterns = [
        r'exec\(', r'eval\(', r'open\(', r'os\.system',
        r'subprocess\.run', r'__import__\('
    ]
    for pattern in dangerous_patterns:
        if re.search(pattern, content, re.IGNORECASE):
            return {'issue': 'unsafe_code', 'pattern': pattern}
    return None

def track_token_usage(messages, budget=5000):
    total_tokens = sum(len(msg.get('content', '')) for msg in messages)
    if total_tokens > budget:
        return {'issue': 'token_exceeded', 'tokens_used': total_tokens, 'budget': budget}
    return None

