    last_msg = messages[-1].get('content', '')
    if '```python' in last_msg and any(keyword in last_msg for keyword in ['exec', 'eval', 'os.system']):
        return "CODE_REJECTED: Unsafe operations detected. Use safe alternatives."
    return None

agent.register_reply([None, safe_code_filter])

def budget_enforcer(self, messages, sender, config):
